    int maxProd = arr[0];
    int currMax = arr[0];
    int currMin = arr[0];

    for (int i = 1; i < n; i++) {
        int num = arr[i];

        // Swap currMax and currMin if negative
        if (num < 0) {
            int temp = currMax;
            currMax = currMin;
            currMin = temp;
        }

        // Update current max and min
        currMax = max(num, currMax * num);
        currMin = min(num, currMin * num);

        // Update overall maximum
        maxProd = max(maxProd, currMax);
    }

    return maxProd;
}

