function maxProduct(nums) {
    if (nums.length === 0) return 0;

    // Initialize using 32-bit integer simulation
    let maxProd = nums[0] | 0;
    let currMax = nums[0] | 0;
    let currMin = nums[0] | 0;

    for (let i = 1; i < nums.length; i++) {
        let num = nums[i] | 0;

        // Swap currMax and currMin if negative
        if (num < 0) {
            let temp = currMax;
            currMax = currMin;
            currMin = temp;
        }

        currMax = Math.max(num, (currMax * num) | 0) | 0;
        currMin = Math.min(num, (currMin * num) | 0) | 0;

        maxProd = Math.max(maxProd, currMax) | 0;
    }

    return maxProd;
}
